    type Token = { type: 'NUM' | 'PLUS' | 'MINUS' | 'MUL' | 'DIV' | 'LPAREN' | 'RPAREN' } | null;

    function tokenize(str: string): Token[] {
        const tokens: Token[] = [];
         let i = 0;
         while (i < str.length) {
            const char = str[i];
            if (/\s/.test(char)) {
                i++;
                continue;
            }
            if (/\d/.test(char)) {
                let num = "";
                while (i < str.length && /\d/.test(str[i])) {
                    num += str[i];
                    i++;
                }
                tokens.push({ type: 'NUM', value: parseInt(num) });
                continue;
            }
            if (char === '+') { tokens.push({ type: 'PLUS' }); i++; }
            else if (char === '-') { tokens.push({ type: 'MINUS' }); i++; }
            else if (char === '*') { tokens.push({ type: 'MUL' }); i++; }
            else if (char === '/') { tokens.push({ type: 'DIV' }); i++; }
            else if (char === '(') { tokens.push({ type: 'LPAREN' }); i++; }
            else if (char === ')')) { tokens.push({ type: 'RPAREN' }); i++; }
            else { i++; }
        }
        return tokens;
    }
